import base64
import html
import uuid
from datetime import datetime, timezone

import requests


def build_saml_authn_request(destination_url, issuer, acs_url, name_id, relay_state=None):
    issue_instant = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
    request_id = "_" + str(uuid.uuid4())

    saml_xml = (
        '<?xml version="1.0" encoding="UTF-8"?>'
        '<samlp:AuthnRequest '
        'xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol" '
        'xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion" '
        f'ID="{html.escape(request_id)}" '
        'Version="2.0" '
        f'IssueInstant="{html.escape(issue_instant)}" '
        f'Destination="{html.escape(destination_url)}" '
        f'AssertionConsumerServiceURL="{html.escape(acs_url)}">'
        f'<saml:Issuer>{html.escape(issuer)}</saml:Issuer>'
        '<saml:Subject>'
        f'<saml:NameID>{html.escape(name_id)}</saml:NameID>'
        '</saml:Subject>'
        '</samlp:AuthnRequest>'
    )

    saml_request = base64.b64encode(saml_xml.encode("utf-8")).decode("ascii")
    form_data = {"SAMLRequest": saml_request}

    if relay_state is not None:
        form_data["RelayState"] = relay_state

    response = requests.post(destination_url, data=form_data, timeout=30)
    return {
        "request_id": request_id,
        "issue_instant": issue_instant,
        "xml": saml_xml,
        "encoded_request": saml_request,
        "status_code": response.status_code,
        "response_text": response.text,
    }


